package com.xoxo.pos.expenses;import jakarta.persistence.*;import java.math.BigDecimal;import java.time.LocalDateTime;@Entity @Table(name="expenses") public class Expense{@Id @GeneratedValue(strategy=GenerationType.IDENTITY) private Long id;private String concept;@Column(nullable=false,precision=10,scale=2) private BigDecimal amount;private LocalDateTime createdAt=LocalDateTime.now();private String notes;public Long getId(){return id;}public String getConcept(){return concept;}public BigDecimal getAmount(){return amount;}public LocalDateTime getCreatedAt(){return createdAt;}public String getNotes(){return notes;}public void setId(Long id){this.id=id;}public void setConcept(String concept){this.concept=concept;}public void setAmount(BigDecimal amount){this.amount=amount;}public void setCreatedAt(LocalDateTime createdAt){this.createdAt=createdAt;}public void setNotes(String notes){this.notes=notes;}}
